library(haven); library(dplyr); library(readr); w1 <- read_delim("data/input/wave_one_lsype_young_person_2020.tab", "\t", show_col_types=FALSE); w4 <- read_delim("data/input/wave_four_lsype_young_person_2020.tab", "\t", show_col_types=FALSE); w5 <- read_delim("data/input/wave_five_lsype_young_person_2020.tab", "\t", show_col_types=FALSE); w6 <- read_delim("data/input/wave_six_lsype_young_person_2020.tab", "\t", show_col_types=FALSE); w7 <- read_delim("data/input/wave_seven_lsype_young_person_2020.tab", "\t", show_col_types=FALSE); w8 <- read_delim("data/input/ns8_2015_derived.tab", "\t", show_col_types=FALSE); w9 <- read_delim("data/input/ns9_2022_main_interview.tab", "\t", show_col_types=FALSE); d <- w1 %>% select(NSID) %>% full_join(w4 %>% select(NSID, W4nsseccatYP), by="NSID") %>% full_join(w5 %>% select(NSID, W5nsseccatYP), by="NSID") %>% full_join(w6 %>% select(NSID, w6nsseccatYP), by="NSID") %>% full_join(w7 %>% select(NSID, W7NSSECCat), by="NSID") %>% full_join(w8 %>% select(NSID, W8DNSSEC17, W8DACTIVITYC), by="NSID") %>% full_join(w9 %>% select(NSID, W9NSSEC), by="NSID"); d <- d %>% rename(nssec17=W4nsseccatYP, nssec18=W5nsseccatYP, nssec19=w6nsseccatYP, nssec20=W7NSSECCat, nssec25=W8DNSSEC17, nssec32=W9NSSEC); h47 <- function(x) case_when(x==-99~-3, x==-91~-1, TRUE~x); h89 <- function(x) case_when(x==-9~-9, x==-8~-8, x==-1~-1, TRUE~x); d <- d %>% mutate(nssec17=h47(nssec17), nssec18=h47(nssec18), nssec19=h47(nssec19), nssec20=h47(nssec20), nssec25=h89(nssec25), nssec32=h89(nssec32)); d <- d %>% mutate(across(starts_with("nssec"), ~ifelse(is.na(.), -3, .))); col <- function(x) case_when(x>=1 & x<=17 ~ as.integer(floor(x)), TRUE~as.integer(x)); d <- d %>% mutate(across(starts_with("nssec"), col)); d <- d %>% mutate(nssec25=case_when((nssec25<1 | nssec25>17) & W8DACTIVITYC==5 ~ 15, TRUE~nssec25)) %>% select(-W8DACTIVITYC); d <- d %>% select(NSID, nssec17, nssec18, nssec19, nssec20, nssec25, nssec32); dir.create("data/output", recursive=TRUE, showWarnings=FALSE); write_csv(d, "data/output/cleaned_data.csv"); cat("Done\n")